const { BigQuery } = require('@google-cloud/bigquery');
const bigquery = new BigQuery();

const MEMORY_LIMIT_MB = 8192;
const TIMEOUT_SECONDS = 540;
const MAX_RESULTS_PER_QUERY = 100000;
const BATCH_SIZE = 10000;

function validateInput(data) {
  if (!data) {
    throw new Error('Request data is required');
  }
  
  const { datasetId, tableId, aggregationConfig } = data;
  
  if (!datasetId || typeof datasetId !== 'string' || !/^[a-zA-Z0-9_]+$/.test(datasetId)) {
    throw new Error('Invalid datasetId');
  }
  
  if (!tableId || typeof tableId !== 'string' || !/^[a-zA-Z0-9_]+$/.test(tableId)) {
    throw new Error('Invalid tableId');
  }
  
  if (!aggregationConfig || typeof aggregationConfig !== 'object') {
    throw new Error('Invalid aggregationConfig');
  }
  
  return { datasetId, tableId, aggregationConfig };
}

function sanitizeIdentifier(identifier) {
  return identifier.replace(/[^a-zA-Z0-9_]/g, '');
}

function buildAggregationQuery(projectId, datasetId, tableId, config) {
  const safeDatasetId = sanitizeIdentifier(datasetId);
  const safeTableId = sanitizeIdentifier(tableId);
  
  const { groupBy, aggregations, filters, orderBy, limit } = config;
  
  let query = 'SELECT ';
  
  if (groupBy && Array.isArray(groupBy) && groupBy.length > 0) {
    const safeGroupBy = groupBy
      .filter(col => typeof col === 'string' && /^[a-zA-Z0-9_]+$/.test(col))
      .map(col => sanitizeIdentifier(col));
    
    if (safeGroupBy.length === 0) {
      throw new Error('Invalid groupBy columns');
    }
    
    query += safeGroupBy.join(', ') + ', ';
  }
  
  if (aggregations && Array.isArray(aggregations) && aggregations.length > 0) {
    const safeAggregations = aggregations
      .filter(agg => {
        return agg && 
               typeof agg.function === 'string' && 
               /^(COUNT|SUM|AVG|MIN|MAX|STDDEV|VARIANCE)$/i.test(agg.function) &&
               typeof agg.column === 'string' && 
               /^[a-zA-Z0-9_*]+$/.test(agg.column) &&
               (!agg.alias || /^[a-zA-Z0-9_]+$/.test(agg.alias));
      })
      .map(agg => {
        const func = agg.function.toUpperCase();
        const col = sanitizeIdentifier(agg.column);
        const alias = agg.alias ? sanitizeIdentifier(agg.alias) : `${func.toLowerCase()}_${col}`;
        return `${func}(${col}) AS ${alias}`;
      });
    
    if (safeAggregations.length === 0) {
      throw new Error('Invalid aggregations');
    }
    
    query += safeAggregations.join(', ');
  } else {
    query += '*';
  }
  
  query += ` FROM \`${projectId}.${safeDatasetId}.${safeTableId}\``;
  
  if (filters && Array.isArray(filters) && filters.length > 0) {
    const safeFilters = filters
      .filter(filter => {
        return filter &&
               typeof filter.column === 'string' &&
               /^[a-zA-Z0-9_]+$/.test(filter.column) &&
               typeof filter.operator === 'string' &&
               /^(=|!=|>|<|>=|<=|IN|NOT IN|LIKE|IS NULL|IS NOT NULL)$/i.test(filter.operator) &&
               (filter.operator.match(/NULL$/i) || filter.value !== undefined);
      })
      .map(filter => {
        const col = sanitizeIdentifier(filter.column);
        const op = filter.operator.toUpperCase();
        
        if (op.match(/NULL$/)) {
          return `${col} ${op}`;
        }
        
        if (op === 'IN' || op === 'NOT IN') {
          if (!Array.isArray(filter.value)) {
            return null;
          }
          const values = filter.value
            .filter(v => typeof v === 'string' || typeof v === 'number')
            .map(v => typeof v === 'string' ? `'${v.replace(/'/g, "''")}'` : v)
            .join(', ');
          return values ? `${col} ${op} (${values})` : null;
        }
        
        let value = filter.value;
        if (typeof value === 'string') {
          value = `'${value.replace(/'/g, "''")}'`;
        } else if (typeof value === 'number') {
          value = value.toString();
        } else {
          return null;
        }
        
        return `${col} ${op} ${value}`;
      })
      .filter(f => f !== null);
    
    if (safeFilters.length > 0) {
      query += ' WHERE ' + safeFilters.join(' AND ');
    }
  }
  
  if (groupBy && Array.isArray(groupBy) && groupBy.length > 0) {
    const safeGroupBy = groupBy
      .filter(col => typeof col === 'string' && /^[a-zA-Z0-9_]+$/.test(col))
      .map(col => sanitizeIdentifier(col));
    
    if (safeGroupBy.length > 0) {
      query += ' GROUP BY ' + safeGroupBy.join(', ');
    }
  }
  
  if (orderBy && Array.isArray(orderBy) && orderBy.length > 0) {
    const safeOrderBy = orderBy
      .filter(order => {
        return order &&
               typeof order.column === 'string' &&
               /^[a-zA-Z0-9_]+$/.test(order.column) &&
               (!order.direction || /^(ASC|DESC)$/i.test(order.direction));
      })
      .map(order => {
        const col = sanitizeIdentifier(order.column);
        const dir = order.direction ? order.direction.toUpperCase() : 'ASC';
        return `${col} ${dir}`;
      });
    
    if (safeOrderBy.length > 0) {
      query += ' ORDER BY ' + safeOrderBy.join(', ');
    }
  }
  
  if (limit && typeof limit === 'number' && limit > 0 && limit <= MAX_RESULTS_PER_QUERY) {
    query += ` LIMIT ${Math.floor(limit)}`;
  }
  
  return query;
}

async function processInBatches(rows, batchProcessor) {
  const results = [];
  
  for (let i = 0; i < rows.length; i += BATCH_SIZE) {
    const batch = rows.slice(i, i + BATCH_SIZE);
    const batchResult = await batchProcessor(batch, i);
    results.push(batchResult);
  }
  
  return results;
}

async function aggregateData(projectId, datasetId, tableId, aggregationConfig) {
  try {
    const query = buildAggregationQuery(projectId, datasetId, tableId, aggregationConfig);
    
    console.log('Executing query:', query);
    
    const options = {
      query: query,
      location: 'US',
      maximumBytesBilled: '1000000000000',
      timeoutMs: (TIMEOUT_SECONDS - 30) * 1000,
      useLegacySql: false,
    };
    
    const [job] = await bigquery.createQueryJob(options);
    console.log(`Job ${job.id} started.`);
    
    const [rows] = await job.getQueryResults({
      maxResults: MAX_RESULTS_PER_QUERY,
      timeoutMs: (TIMEOUT_SECONDS - 30) * 1000,
    });
    
    console.log(`Query returned ${rows.length} rows.`);
    
    const processedResults = await processInBatches(rows, async (batch, offset) => {
      return {
        offset: offset,
        count: batch.length,
        data: batch,
      };
    });
    
    const metadata = await job.getMetadata();
    const statistics = metadata[0].statistics;
    
    return {
      success: true,
      rowCount: rows.length,
      batches: processedResults.length,
      statistics: {
        totalBytesProcessed: statistics.totalBytesProcessed,
        totalBytesBilled: statistics.totalBytesBilled,
        cacheHit: statistics.query.cacheHit,
        queryPlan: statistics.query.queryPlan ? statistics.query.queryPlan.length : 0,
      },
      results: processedResults,
    };
    
  } catch (error) {
    console.error('Error processing BigQuery data:', error);
    throw error;
  }
}

exports.processBigData = async (req, res) => {
  const startTime = Date.now();
  
  res.set('X-Content-Type-Options', 'nosniff');
  res.set('X-Frame-Options', 'DENY');
  res.set('X-XSS-Protection', '1; mode=block');
  res.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  
  try {
    if (req.method !== 'POST') {
      res.status(405).json({ error: 'Method not allowed' });
      return;
    }
    
    const contentType = req.get('content-type') || '';
    if (!contentType.includes('application/json')) {
      res.status(400).json({ error: 'Content-Type must be application/json' });
      return;
    }
    
    const { datasetId, tableId, aggregationConfig } = validateInput(req.body);
    
    const projectId = process.env.GCP_PROJECT || process.env.GCLOUD_PROJECT;
    if (!projectId) {
      throw new Error('GCP Project ID not configured');
    }
    
    console.log(`Processing dataset: ${datasetId}, table: ${tableId}`);
    console.log(`Memory limit: ${MEMORY_LIMIT_MB}MB, Timeout: ${TIMEOUT_SECONDS}s`);
    
    const result = await aggregateData(projectId, datasetId, tableId, aggregationConfig);
    
    const executionTime = Date.now() - startTime;
    console.log(`Execution completed in ${executionTime}ms`);
    
    res.status(200).json({
      ...result,
      executionTimeMs: executionTime,
      memoryLimitMB: MEMORY_LIMIT_MB,
      timeoutSeconds: TIMEOUT_SECONDS,
    });
    
  } catch (error) {
    console.error('Function error:', error);
    
    const executionTime = Date.now() - startTime;
    
    const statusCode = error.message.includes('Invalid') || 
                       error.message.includes('required') ? 400 : 500;
    
    res.status(statusCode).json({
      success: false,
      error: error.message,
      executionTimeMs: executionTime,
    });
  }
};